from django.db import models


class ArticleQuerySet(models.QuerySet):
    """Custom queryset for articles."""

    def published(self):
        return self.filter(status='published')

    def draft(self):
        return self.filter(status='draft')

    def by_author(self, author):
        return self.filter(author=author)

    def recent(self, days=30):
        from django.utils import timezone
        from datetime import timedelta
        cutoff = timezone.now() - timedelta(days=days)
        return self.filter(created_at__gte=cutoff)


class ArticleManager(models.Manager):
    """Manager using ArticleQuerySet."""

    def get_queryset(self):
        return ArticleQuerySet(self.model, using=self._db)

    def published(self):
        return self.get_queryset().published()

    def recent(self, days=30):
        return self.get_queryset().recent(days)


# Alternative DRY pattern: Manager from QuerySet
# No need to duplicate methods
ArticleManager = ArticleQuerySet.as_manager()

from django.db import models
from django.utils import timezone


class SoftDeleteQuerySet(models.QuerySet):
    """QuerySet that supports soft delete operations."""

    def delete(self):
        """Soft delete all objects in queryset."""
        return self.update(deleted_at=timezone.now())

    def hard_delete(self):
        """Permanently delete all objects in queryset."""
        return super().delete()

    def restore(self):
        """Restore all soft-deleted objects in queryset."""
        return self.update(deleted_at=None)

    def active(self):
        """Return only non-deleted objects."""
        return self.filter(deleted_at__isnull=True)

    def deleted(self):
        """Return only deleted objects."""
        return self.filter(deleted_at__isnull=False)


class SoftDeleteManager(models.Manager):
    """Manager that excludes soft-deleted records by default."""

    def get_queryset(self):
        return SoftDeleteQuerySet(self.model, using=self._db).active()

    def with_deleted(self):
        """Include soft-deleted records."""
        return SoftDeleteQuerySet(self.model, using=self._db)

    def deleted_only(self):
        """Return only soft-deleted records."""
        return SoftDeleteQuerySet(self.model, using=self._db).deleted()


class AllObjectsManager(models.Manager):
    """Manager that includes all records (deleted and active)."""

    def get_queryset(self):
        return SoftDeleteQuerySet(self.model, using=self._db)


class SoftDeleteMixin(models.Model):
    """Adds soft delete capability."""

    deleted_at = models.DateTimeField(null=True, blank=True, db_index=True)

    objects = SoftDeleteManager()
    all_objects = AllObjectsManager()

    class Meta:
        abstract = True

    def delete(self, using=None, keep_parents=False):
        """Soft delete instead of hard delete."""
        self.deleted_at = timezone.now()
        self.save(update_fields=['deleted_at', 'updated_at'])

    def hard_delete(self):
        """Permanently delete from database."""
        super().delete()

    def restore(self):
        """Restore soft-deleted record."""
        self.deleted_at = None
        self.save(update_fields=['deleted_at', 'updated_at'])

    @property
    def is_deleted(self) -> bool:
        return self.deleted_at is not None

from django.db import models
from django.conf import settings


class TenantManager(models.Manager):
    """Manager that filters by current tenant."""

    def get_queryset(self):
        from .middleware import get_current_tenant
        tenant = get_current_tenant()
        if tenant:
            return super().get_queryset().filter(tenant=tenant)
        return super().get_queryset()


class TenantAwareModel(models.Model):
    """Abstract base for tenant-scoped models."""

    tenant = models.ForeignKey(
        'tenants.Tenant',
        on_delete=models.CASCADE,
        related_name='%(class)s_set',
    )

    objects = TenantManager()
    unscoped = models.Manager()  # Access all tenants (admin only)

    class Meta:
        abstract = True

    def save(self, *args, **kwargs):
        if not self.tenant_id:
            from .middleware import get_current_tenant
            self.tenant = get_current_tenant()
        super().save(*args, **kwargs)

from django.db import models
class Order(models.Model): """Ownership relationship: orders shouldn't cascade-delete when user leaves.""" user = models.ForeignKey(User, on_delete=models.PROTECT)
class OrderItem(models.Model): """Composition: items are part of order and meaningless without it.""" order = models.ForeignKey(Order, on_delete=models.CASCADE)
class Task(models.Model): """Assignment: task survives when user leaves, assignment cleared.""" assigned_to = models.ForeignKey( User, on_delete=models.SET_NULL, null=True, blank=True )
class Comment(models.Model): """Attribution: preserve comment, clear author when user deleted.""" author = models.ForeignKey( User, on_delete=models.SET_NULL, null=True, blank=True )
